<?php
session_start();
require_once '../config/config.php';
if(!isAdmin()) { header('Location: login.php'); exit; }
if(isset($_POST['update_stock'])) {
    $stmt = $pdo->prepare("UPDATE products SET stock_quantity=? WHERE id=?");
    $stmt->execute([$_POST['stock_quantity'], $_POST['product_id']]);
    header('Location: inventory.php?msg=updated');
    exit;
}
$products = $pdo->query("SELECT * FROM products ORDER BY stock_quantity ASC")->fetchAll();
$lowStock = array_filter($products, function($p) { return $p['stock_quantity'] < 10 && $p['stock_quantity'] > 0; });
$outOfStock = array_filter($products, function($p) { return $p['stock_quantity'] == 0; });
$inStock = array_filter($products, function($p) { return $p['stock_quantity'] >= 10; });
?>
<!DOCTYPE html>
<html><head><title>Inventory Management - African Fashion</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.1.3/dist/css/bootstrap.min.css" rel="stylesheet"><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0/css/all.min.css"><style>.sidebar{min-height:100vh;background:#1a1a2e;}.sidebar .nav-link{color:white;padding:12px20px;}.sidebar .nav-link:hover{background:#f36f25;}.stock-low{background:#fff3cd;}.stock-out{background:#f8d7da;}</style></head>
<body><div class="container-fluid"><div class="row"><div class="col-md-2 p-0 sidebar"><div class="text-center py-3"><h5 class="text-white"><i class="fas fa-tshirt"></i> Admin Panel</h5></div><nav class="nav flex-column"><a class="nav-link" href="index.php">Dashboard</a><a class="nav-link" href="products.php">Products</a><a class="nav-link" href="orders.php">Orders</a><a class="nav-link active" href="inventory.php">Inventory</a><a class="nav-link" href="logout.php">Logout</a></nav></div><div class="col-md-10 p-4"><h2>Inventory Management</h2><div class="row mb-4"><div class="col-md-4"><div class="card text-white bg-success"><div class="card-body"><h3><?php echo count($inStock); ?></h3><p>In Stock (≥10)</p></div></div></div><div class="col-md-4"><div class="card text-white bg-warning"><div class="card-body"><h3><?php echo count($lowStock); ?></h3><p>Low Stock (<10)</p></div></div></div><div class="col-md-4"><div class="card text-white bg-danger"><div class="card-body"><h3><?php echo count($outOfStock); ?></h3><p>Out of Stock</p></div></div></div></div><?php if(isset($_GET['msg'])): ?><div class="alert alert-success">Stock updated successfully!</div><?php endif; ?><?php if(count($lowStock) > 0): ?><div class="alert alert-warning"><h5><i class="fas fa-exclamation-triangle"></i> Low Stock Alert!</h5><?php foreach($lowStock as $p): ?><div><strong><?php echo htmlspecialchars($p['name']); ?></strong> - Only <?php echo $p['stock_quantity']; ?> units remaining. <strong>Restock needed!</strong></div><?php endforeach; ?></div><?php endif; ?><div class="table-responsive"><table class="table table-bordered"><thead class="table-dark"><tr><th>Product</th><th>Current Stock</th><th>Units Sold</th><th>Status</th><th>Update Stock</th></tr></thead><tbody><?php foreach($products as $p): $rowClass = $p['stock_quantity']==0?'stock-out':($p['stock_quantity']<10?'stock-low':''); $images = $p['images'] ? json_decode($p['images'], true) : ['placeholder.jpg']; ?><tr class="<?php echo $rowClass; ?>"><td><img src="../assets/uploads/<?php echo $images[0]; ?>" width="50" height="50" style="object-fit:cover" onerror="this.src='https://via.placeholder.com/50'"> <?php echo htmlspecialchars($p['name']); ?></td><td><strong><?php echo $p['stock_quantity']; ?></strong> units</td><td><?php echo $p['sold_count']; ?> units</td><td><?php if($p['stock_quantity']==0): ?><span class="badge bg-danger">OUT OF STOCK</span><?php elseif($p['stock_quantity']<10): ?><span class="badge bg-warning">LOW STOCK</span><?php else: ?><span class="badge bg-success">IN STOCK</span><?php endif; ?></td><td><form method="POST" class="d-flex"><input type="hidden" name="product_id" value="<?php echo $p['id']; ?>"><input type="number" name="stock_quantity" value="<?php echo $p['stock_quantity']; ?>" class="form-control me-2" style="width:100px" min="0"><button type="submit" name="update_stock" class="btn btn-primary btn-sm">Update</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div></div></body>
</html>